        continue
    b_id = row['business_id'].split('_')[1]
    if b_id in reviewed_businesses:
        attrs = row.get('attributes')
        if attrs:
            has_parking = False

            # Check BikeParking
            if attrs.get('BikeParking') == 'True':
                has_parking = True

            # Check BusinessParking
            bp = attrs.get('BusinessParking')
            if bp and bp != 'None':
                try:
                    bp_dict = ast.literal_eval(bp)
                    if any(bp_dict.values()):
                        has_parking = True
                except:
                    pass

            if has_parking:
                count += 1

print(f"Count: {count}")

